const LOGO="data:image png;base64,",COLORS="\n:root {\n    --bgc: #bfbfbf;\n    --textc: #111111;\n    --ltextc: #7d7d7d;\n    --accentc: #007bff;\n    --border: #FF9CE9;\n    --bg-nav: lightslategray;\n    --bg-nav-hover: lightpink;\n}\n@media (prefers-color-scheme: dark) {\n    :root {\n        --bgc: #111111;\n        --textc: #eeeeee;\n        --ltextc: #bfbfbf;\n        --accentc: #375a7f;\n        --border: #D10092;\n        --bg-nav: gray;\n        --bg-nav-hover: pink;\n    }\n}",App={state:{page:"home",user:"Guest",items:["Разработка на Rust","Настройка Arch Linux","Docker контейнеры"]},init(){console.log("SPA Приложение запущено!"),this.render(),this.initNavigation()},render(){const n=document.getElementById("app");let e="";"home"===this.state.page?e=`\n\n            <header>\n             <img class="logo-img pixelated" src="${LOGO}"/>\n            </header>\n            <nav>\n            <a href="#">FAQ</a>\n            <a href="#">Поддержка</a>\n            <a href="#">Контакты</a>\n            </nav>\n            <div class="container">\n            <h1>Добро пожаловать в HomeLab Dashboard</h1>\n            <p>Привет, ${this.state.user}. Выберите раздел:</p>\n            <ul class="menu">\n            <li><a href="#" data-link="projects">Мои проекты</a></li>\n            <li><a href="#" data-link="settings">Настройки сервера</a></li>\n            </ul>\n            </div>\n            `:"projects"===this.state.page&&(e=`\n            <div class="container">\n            <h1>Мои проекты</h1>\n            <ul>\n            ${this.state.items.map(n=>`<li>${n}</li>`).join("")}\n            </ul>\n            <button class="btn-back" data-link="home">← Назад</button>\n            </div>\n            `),n.innerHTML=e,this.applyStyles()},initNavigation(){window.addEventListener("click",n=>{const e=n.target.closest("[data-link]");if(e){n.preventDefault();const t=e.getAttribute("data-link");this.state.page=t,history.pushState({page:t},"",`/${t}`),this.render()}}),window.addEventListener("popstate",n=>{n.state&&n.state.page&&(this.state.page=n.state.page,this.render())})},applyStyles(){if(document.getElementById("app-styles"))return;const n=document.createElement("style");n.id="app-styles",n.textContent=`\n        ${COLORS}\n        .logo-img {\n            height: 100px; /* Регулируй высоту логотипа здесь */\n            width: auto;\n            display: block;\n            margin: 0 auto;\n        }\n        nav {\n            display: flex;\n            justify-content: center;\n            gap: 15px;\n            background-color: var(--bg-nav);\n            padding: 15px;\n            position: sticky;\n            top: 0;\n            z-index: 1000;\n        }\n\n        nav a {\n            color: white;\n            text-decoration: none;\n            padding: 8px 16px;\n            border-radius: 4px;\n            transition: 0.3s;\n            font-size: 14px;\n        }\n\n        nav a:hover {\n            background-color: var(--bg-nav-hover);\n        }\n\n        .pixelated {\n            /* Для Safari и старых версий iOS */\n            image-rendering: -webkit-optimize-contrast;\n\n            /* Для Firefox */\n            image-rendering: crisp-edges;\n\n            /* Стандартное свойство (работает в Chrome, Edge, Opera) */\n            /* Оно заставляет браузер использовать метод "ближайшего соседа" при масштабировании */\n            image-rendering: pixelated;\n\n            /* Убираем сглаживание, если оно применяется */\n            -ms-interpolation-mode: nearest-neighbor; /* Для старых IE */\n        }\n        .container { padding: 40px; max-width: 800px; margin: 0 auto; }\n        h1 { color: var(--textc); border-bottom: 2px solid var(--bgc); padding-bottom: 10px; }\n        .menu { list-style: none; padding: 0; display: flex; gap: 20px; }\n        .menu a { color: var(--textc); text-decoration: none; font-weight: bold; }\n        .btn-back { margin-top: 20px; padding: 10px 20px; background: var(--bgc); color: var(--textc); border: none; cursor: pointer; border-radius: 5px; }\n        li { margin: 10px 0; font-size: 1.1em; }\n        `,document.head.appendChild(n)}};App.init();